SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG_FINAL AS ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1_CONTACT AS POST_CODE1, CITY1_CONTACT AS CITY1, CITY2_CONTACT AS CITY2, EMAIL
FROM J09C_enriched
WHERE ENTSCHEIDUNG_FINAL = 'MANDATORY_READING';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG_FINAL AS ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1_CONTACT AS POST_CODE1, CITY1_CONTACT AS CITY1, CITY2_CONTACT AS CITY2, EMAIL
FROM J09C_enriched
WHERE ENTSCHEIDUNG_FINAL <> 'MANDATORY_READING' OR ENTSCHEIDUNG_FINAL IS NULL;
